-- Luke Chapter 22
-- Theme: The Last Supper, Betrayal, Gethsemane, Arrest, and Peter's Denial
-- 71 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 22,
  'Luke 22 is the longest chapter in Luke''s Gospel and the theological center of the Passion Narrative. It opens with the conspiracy of the chief priests and scribes to eliminate Jesus, into which Judas — entered by Satan himself (v.3) — inserts himself as the betrayer (vv.1-6). The Passover preparations (vv.7-13) demonstrate Jesus'' sovereign foreknowledge: he directs Peter and John to find a man carrying a water jar (an unusual sight, as water-carrying was women''s work), who leads them to a furnished upper room. Every detail proceeds according to a divine script that the conspirators cannot disrupt.' ||
  'The Last Supper (vv.14-38) is the interpretive heart of the chapter. Jesus reinterprets the Passover elements christologically: the bread becomes "my body which is given for you" (v.19), the cup becomes "the new testament in my blood, which is shed for you" (v.20). The "new testament" (hē kainē diathēkē) alludes to Jeremiah 31:31-34, the prophecy of a new covenant replacing the Mosaic covenant. A dispute over greatness among the disciples (vv.24-30) provokes Jesus''s teaching on servant leadership: "he that is greatest among you, let him be as the younger; and he that is chief, as he that doth serve" (v.26). Jesus promises Peter that he has prayed for his faith not to fail, while simultaneously predicting his threefold denial (vv.31-34). The "two swords" dialogue (vv.35-38) signals the transition from the mission of peace to the hour of confrontation.' ||
  'The Gethsemane scene (vv.39-46) is distinctively Lucan: Luke alone records the angel strengthening Jesus (v.43) and the sweat "as it were great drops of blood" (v.44) — medical language (thromboi haimatos) suggesting hematidrosis, a condition of extreme anguish. Jesus''s arrest (vv.47-53) features Judas''s kiss, the healing of the severed ear (only in Luke), and Jesus''s declaration that "this is your hour, and the power of darkness" (v.53). Peter''s denial (vv.54-62) reaches its devastating climax when "the Lord turned, and looked upon Peter" (v.61) — a detail unique to Luke, turning the denial into a personal encounter. The chapter closes with the mockery and beating of Jesus by his guards (vv.63-65) and his appearance before the Sanhedrin (vv.66-71), where his response to their question — "Ye say that I am" (v.70) — is an affirmation couched in the language of judicial reserve.',
  'The Last Supper, Betrayal, Gethsemane, Arrest, and Peter''s Denial',
  'διαθήκη (diathēkē)',
  'diathēkē means covenant, testament, a binding arrangement — from diatithēmi (to arrange, to dispose). In v.20, Jesus declares the cup to be "the new testament in my blood" (hē kainē diathēkē en tō haimati mou), establishing the new covenant prophesied in Jeremiah 31:31-34. The word diathēkē in Greek can mean either a bilateral covenant or a unilateral testament (a will executed at death); both senses converge at the cross, where Jesus''s death is simultaneously the sacrifice that ratifies the covenant and the testamentary act that bequeaths its blessings to the heirs. The old covenant was ratified by animal blood (Exod 24:8); the new covenant is ratified by the blood of God''s own Son. Every element of the Passover meal — unleavened bread, the cup of blessing, the lamb — finds its fulfillment in Christ''s self-offering.',
  '["The Conspiracy: Chief Priests, Scribes, and Judas (vv.1-6)","Preparation for the Passover (vv.7-13)","The Last Supper: New Covenant in His Blood (vv.14-23)","Dispute Over Greatness and Servant Leadership (vv.24-30)","Peter''s Denial Predicted and the Two Swords (vv.31-38)","Gethsemane: Agony, Angel, and Arrest (vv.39-53)","Peter''s Denial and the Lord''s Look (vv.54-62)","Mockery, Beating, and the Sanhedrin Trial (vv.63-71)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Now the feast of unleavened bread drew nigh, which is called the Passover.', 'Ἤγγιζεν δὲ ἡ ἑορτὴ τῶν ἀζύμων ἡ λεγομένη Πάσχα.', 'Ēngizen de hē heortē tōn azumōn hē legomenē Pascha.', '"The feast of unleavened bread" (hē heortē tōn azumōn — the festival of the unleavened loaves; azumos from a-negative + zumē/leaven) — technically distinct from Passover (Passover on Nisan 14, Unleavened Bread from Nisan 15-21), but by the first century the terms were used interchangeably for the entire eight-day celebration. "Which is called the Passover" (hē legomenē Pascha — the one called Passover; Pascha from Hebrew pesach/to pass over, commemorating the angel of death passing over Israelite homes in Exodus 12). Luke''s identification of the two feasts provides a Gentile audience with necessary context. The theological irony is profound: the feast celebrating Israel''s liberation from Egypt will become the occasion for the ultimate Passover — the Lamb of God''s self-offering.', NULL),
  (2, 'And the chief priests and scribes sought how they might kill him; for they feared the people.', 'καὶ ἐζήτουν οἱ ἀρχιερεῖς καὶ οἱ γραμματεῖς τὸ πῶς ἀνέλωσιν αὐτόν· ἐφοβοῦντο γὰρ τὸν λαόν.', 'kai ezētoun hoi archiereis kai hoi grammateis to pōs anelōsin auton; ephobounto gar ton laon.', '"Sought how they might kill him" (ezētoun...to pōs anelōsin auton — were seeking the how they might destroy him; anelōsin from anaireō = to take up, to eliminate, to kill) — the imperfect tense indicates ongoing, deliberate plotting. "For they feared the people" (ephobounto gar ton laon — for they were fearing the people) — the obstacle to their plan is the crowd''s enthusiasm for Jesus (19:48; 20:19; 21:38). The religious leadership cannot act openly; they need a covert operation. This constraint makes Judas''s offer (v.3-6) providentially useful to their conspiracy while remaining providentially determined by God''s redemptive plan.', NULL),
  (3, 'Then entered Satan into Judas surnamed Iscariot, being of the number of the twelve.', 'Εἰσῆλθεν δὲ Σατανᾶς εἰς Ἰούδαν τὸν καλούμενον Ἰσκαριώτην, ὄντα ἐκ τοῦ ἀριθμοῦ τῶν δώδεκα·', 'Eisēlthen de Satanas eis Ioudan ton kaloumenon Iskariōtēn, onta ek tou arithmou tōn dōdeka;', '"Then entered Satan into Judas" (Eisēlthen Satanas eis Ioudan — Satan entered into Judas) — Luke and John (13:27) alone attribute Judas''s betrayal to direct Satanic entry. The return of Satan is theologically significant: Luke 4:13 noted that the devil "departed from him for a season" (achri kairou) after the wilderness temptation. That "season" has now ended; Satan returns for the decisive confrontation. "Surnamed Iscariot" (ton kaloumenon Iskariōtēn — the one called Iscariot; probably from Hebrew ish Qerioth, "man of Kerioth," a town in southern Judea, making Judas the only non-Galilean among the Twelve). "Being of the number of the twelve" (onta ek tou arithmou tōn dōdeka) — the phrase intensifies the horror: the betrayer belongs to the innermost circle.', NULL),
  (4, 'And he went his way, and communed with the chief priests and captains, how he might betray him unto them.', 'καὶ ἀπελθὼν συνελάλησεν τοῖς ἀρχιερεῦσιν καὶ στρατηγοῖς τὸ πῶς αὐτοῖς παραδῷ αὐτόν.', 'kai apelthōn sunelalēsen tois archiereusin kai stratēgois to pōs autois paradō auton.', '"Communed with" (sunelalēsen — spoke together with, conferred with; sun + laleō = to talk with, implying a private meeting). "The chief priests and captains" (tois archiereusin kai stratēgois — the chief priests and the Temple captains; stratēgoi were the officers of the Temple guard, a Levitical police force under the authority of the Sanhedrin). Luke uniquely includes the Temple captains, indicating that the arrest will require military coordination. "How he might betray him" (to pōs autois paradō auton — the how he might hand him over to them; paradidōmi = to hand over, to deliver up) — Judas provides the insider intelligence the conspirators need: the time and place where Jesus can be apprehended away from the protective crowds.', NULL),
  (5, 'And they were glad, and covenanted to give him money.', 'καὶ ἐχάρησαν, καὶ συνέθεντο αὐτῷ ἀργύριον δοῦναι.', 'kai echarēsan, kai sunethento autō argurion dounai.', '"They were glad" (echarēsan — they rejoiced; the ironic joy of the conspirators at finding a way to accomplish their murderous plot). "Covenanted to give him money" (sunethento autō argurion dounai — they agreed together to give him silver; suntithēmi = to put together, to agree upon, to contract). Matthew 26:15 specifies the amount as thirty pieces of silver (triakonta arguria), fulfilling Zechariah 11:12-13. Luke''s more general "money" (argurion — silver) keeps the focus on the moral degradation of the transaction: a member of the Twelve sells his Master for payment. The Satanic motivation (v.3) and the financial inducement work together — greed provides the foothold through which Satan operates.', NULL),
  (6, 'And he promised, and sought opportunity to betray him unto them in the absence of the multitude.', 'καὶ ἐξωμολόγησεν, καὶ ἐζήτει εὐκαιρίαν τοῦ παραδοῦναι αὐτὸν ἄτερ ὄχλου αὐτοῖς.', 'kai exōmologēsen, kai ezētei eukairian tou paradounai auton ater ochlou autois.', '"He promised" (exōmologēsen — he consented, he agreed fully; exomologeō can mean to confess or to agree; here the sense is assent to the conspirators'' terms). "Sought opportunity" (ezētei eukairian — was seeking a good opportunity; eukairos from eu/well + kairos/time = a well-timed moment, a favorable occasion). "In the absence of the multitude" (ater ochlou — without a crowd, apart from the throng; ater is a rare preposition meaning without, appearing only here and v.35 in Luke) — the strategy is clear: the crowds protect Jesus, so the arrest must occur when the crowds are absent. Gethsemane at night will provide exactly this opportunity (v.47). The imperfect tense (ezētei — was seeking) indicates ongoing surveillance by Judas.', NULL),
  (7, 'Then came the day of unleavened bread, when the passover must be killed.', 'Ἦλθεν δὲ ἡ ἡμέρα τῶν ἀζύμων, ᾗ ἔδει θύεσθαι τὸ πάσχα.', 'Ēlthen de hē hēmera tōn azumōn, hē edei thuesthai to pascha.', '"The day of unleavened bread" (hē hēmera tōn azumōn — the day of the unleavened loaves) — Nisan 14, the day of preparation when the Passover lamb was slaughtered in the Temple courts between the evening sacrifices (approximately 3-5 PM). "When the passover must be killed" (hē edei thuesthai to pascha — on which it was necessary to sacrifice the Passover; edei = it was divinely necessary, the same word of divine necessity used for the cross in 9:22). The verb thuesthai (to be sacrificed) is specifically sacrificial language. Luke''s theological point is implicit but powerful: on the very day when the Passover lamb must be slain, the true Lamb begins his final preparations.', NULL),
  (8, 'And he sent Peter and John, saying, Go and prepare us the passover, that we may eat.', 'καὶ ἀπέστειλεν Πέτρον καὶ Ἰωάννην εἰπών, Πορευθέντες ἑτοιμάσατε ἡμῖν τὸ πάσχα ἵνα φάγωμεν.', 'kai apesteilen Petron kai Iōannēn eipōn, Poreuthentes hetoimasate hēmin to pascha hina phagōmen.', '"He sent Peter and John" (apesteilen Petron kai Iōannēn — he sent Peter and John; only Luke identifies these two by name; Mark 14:13 says simply "two of his disciples"). Peter and John, the two who will also run to the empty tomb (24:12; John 20:3-4), are entrusted with Passover preparations. "Prepare us the passover" (hetoimasate hēmin to pascha — prepare for us the Passover) — preparation included procuring a lamb, having it slaughtered in the Temple courts, roasting it, and arranging the unleavened bread, bitter herbs, wine, and charoseth for the Seder meal. The command "that we may eat" (hina phagōmen) expresses Jesus'' desire to share this final meal with his disciples (cf. v.15: "with desire I have desired to eat this passover with you").', NULL),
  (9, 'And they said unto him, Where wilt thou that we prepare?', 'οἱ δὲ εἶπαν αὐτῷ, Ποῦ θέλεις ἑτοιμάσωμεν;', 'hoi de eipan autō, Pou theleis hetoimasōmen?', '"Where wilt thou that we prepare?" (Pou theleis hetoimasōmen — Where do you want us to prepare?) — a practical question revealing that no prior arrangement was known to the disciples. Jerusalem during Passover was crowded with hundreds of thousands of pilgrims; finding an available room was no small matter. Jesus'' detailed foreknowledge in vv.10-12 demonstrates his sovereign control of events even as the conspiracy closes around him. The narrative parallels the preparation of the triumphal entry (19:29-34), where Jesus similarly provided precise advance instructions that the disciples found fulfilled exactly as stated.', NULL),
  (10, 'And he said unto them, Behold, when ye are entered into the city, there shall a man meet you, bearing a pitcher of water; follow him into the house where he entereth in.', 'ὁ δὲ εἶπεν αὐτοῖς, Ἰδοὺ εἰσελθόντων ὑμῶν εἰς τὴν πόλιν συναντήσει ὑμῖν ἄνθρωπος κεράμιον ὕδατος βαστάζων· ἀκολουθήσατε αὐτῷ εἰς τὴν οἰκίαν εἰς ἣν εἰσπορεύεται.', 'ho de eipen autois, Idou eiselthontōn humōn eis tēn polin sunantēsei humin anthrōpos keramion hudatos bastazōn; akolouthēsate autō eis tēn oikian eis hēn eisporeuetai.', '"A man meet you, bearing a pitcher of water" (anthrōpos keramion hudatos bastazōn — a man carrying a clay jar of water) — an unmistakable identifying sign, since water-carrying in earthen jars was almost exclusively women''s work; men typically used leather skins. The sign would make the contact person instantly recognizable in the crowded streets. Some scholars suggest this was a pre-arranged signal between Jesus and the homeowner, perhaps designed to keep the location secret from Judas. "Follow him" (akolouthēsate autō — follow him) — the disciples are to shadow this man without explanation, demonstrating trust in Jesus'' instructions.', NULL),
  (11, 'And ye shall say unto the goodman of the house, The Master saith unto thee, Where is the guestchamber, where I shall eat the passover with my disciples?', 'καὶ ἐρεῖτε τῷ οἰκοδεσπότῃ τῆς οἰκίας, Λέγει σοι ὁ Διδάσκαλος, Ποῦ ἐστιν τὸ κατάλυμα ὅπου τὸ πάσχα μετὰ τῶν μαθητῶν μου φάγω;', 'kai ereite tō oikodespotē tēs oikias, Legei soi ho Didaskalos, Pou estin to kataluma hopou to pascha meta tōn mathētōn mou phagō?', '"The goodman of the house" (tō oikodespotē — the master of the household; oikodespotēs from oikos/house + despotēs/master). "The Master saith unto thee" (Legei soi ho Didaskalos — the Teacher says to you) — the title "the Teacher" (ho Didaskalos) functions as an identifying reference, suggesting the homeowner knows who "the Teacher" is. "The guestchamber" (to kataluma — the guest room, the lodging place; the same word used for the "inn" in 2:7 where there was no room for Mary and Joseph; here it refers to a private dining room). The irony is striking: at Jesus'' birth there was no kataluma available; at his death, one is prepared and furnished.', NULL),
  (12, 'And he shall shew you a large upper room furnished: there make ready.', 'κἀκεῖνος ὑμῖν δείξει ἀνάγαιον μέγα ἐστρωμένον· ἐκεῖ ἑτοιμάσατε.', 'kakeinons humin deixei anagaion mega estrōmenon; ekei hetoimasate.', '"A large upper room furnished" (anagaion mega estrōmenon — a large upper room having been spread/furnished; anagaion from ana/up + gē/ground = an upper story room; estrōmenon from strōnnumi/to spread, to furnish with cushions and rugs for reclining at the Passover meal). Upper rooms were the most private and honored spaces in a Jerusalem house, accessed by an external staircase. Tradition identifies this as the Cenacle on the southwestern hill of Jerusalem. "There make ready" (ekei hetoimasate — there prepare) — the preparations would include setting out the Passover elements: the lamb, unleavened bread, bitter herbs, wine mixed with water, and the Seder arrangement.', NULL),
  (13, 'And they went, and found as he had said unto them: and they made ready the passover.', 'ἀπελθόντες δὲ εὗρον καθὼς εἰρήκει αὐτοῖς, καὶ ἡτοίμασαν τὸ πάσχα.', 'apelthontes de heuron kathōs eirēkei autois, kai hētoimasan to pascha.', '"Found as he had said unto them" (heuron kathōs eirēkei autois — they found just as he had told them) — the fulfillment formula: events unfolded precisely according to Jesus'' word (cf. 19:32, "they found even as he had said unto them"). This pattern of prophetic fulfillment within the narrative demonstrates that Jesus moves through his Passion not as a helpless victim but as the sovereign Lord whose word controls events. "They made ready the passover" (hētoimasan to pascha — they prepared the Passover) — the final Passover preparation of the old covenant is complete; the meal that interprets it christologically is about to begin.', NULL),
  (14, 'And when the hour was come, he sat down, and the twelve apostles with him.', 'Καὶ ὅτε ἐγένετο ἡ ὥρα, ἀνέπεσεν, καὶ οἱ δώδεκα ἀπόστολοι σὺν αὐτῷ.', 'Kai hote egeneto hē hōra, anepesen, kai hoi dōdeka apostoloi sun autō.', '"When the hour was come" (hote egeneto hē hōra — when the hour arrived; hōra with the definite article: the hour, the appointed, destined hour) — the word carries more than chronological significance; it is the kairos, the decisive moment in salvation history. "He sat down" (anepesen — he reclined; at Passover, Jews reclined on cushions in the manner of free persons, symbolizing their liberation from Egyptian slavery). "The twelve apostles with him" (hoi dōdeka apostoloi sun autō) — Luke uses the full title "apostles" (apostoloi — sent ones) rather than simply "disciples," perhaps emphasizing their commissioned authority as those who will carry the new covenant message after his departure.', NULL),
  (15, 'And he said unto them, With desire I have desired to eat this passover with you before I suffer:', 'καὶ εἶπεν πρὸς αὐτούς, Ἐπιθυμίᾳ ἐπεθύμησα τοῦτο τὸ πάσχα φαγεῖν μεθ'' ὑμῶν πρὸ τοῦ με παθεῖν·', 'kai eipen pros autous, Epithumia epethumēsa touto to pascha phagein meth'' humōn pro tou me pathein;', '"With desire I have desired" (Epithumia epethumēsa — with longing I have longed; a Semitic intensifying construction using the cognate noun and verb together: I have earnestly desired) — the phrase expresses deep, passionate anticipation. "This passover" (touto to pascha — this specific Passover) — not any Passover but this one, the last one of the old covenant and the first of the new. "Before I suffer" (pro tou me pathein — before I suffer; pathein from paschō = to suffer, the root of "Passion") — Jesus names his suffering explicitly. The longing is not to delay suffering but to share this covenantal meal with his disciples before the cross transforms its meaning permanently. The meal is the interpretive bridge between the old Passover and the new.', NULL),
  (16, 'For I say unto you, I will not any more eat thereof, until it be fulfilled in the kingdom of God.', 'λέγω γὰρ ὑμῖν ὅτι οὐ μὴ φάγω αὐτὸ ἕως ὅτου πληρωθῇ ἐν τῇ βασιλείᾳ τοῦ Θεοῦ.', 'legō gar humin hoti ou mē phagō auto heōs hotou plērōthē en tē basileia tou Theou.', '"I will not any more eat thereof" (ou mē phagō auto — I will certainly not eat it; the double negative of strongest denial) — a vow of abstinence. "Until it be fulfilled in the kingdom of God" (heōs hotou plērōthē en tē basileia tou Theou — until it is fulfilled in the kingdom of God; plēroō = to fill up, to bring to completion) — the Passover itself awaits eschatological fulfillment. The earthly Passover celebrates a historical deliverance; its ultimate fulfillment is the messianic banquet in the consummated kingdom (cf. 13:29; 14:15; Rev 19:9). Jesus looks through the cross to the resurrection and beyond to the final feast. This saying creates an eschatological horizon for every celebration of the Lord''s Supper: it is done "till he come" (1 Cor 11:26).', NULL),
  (17, 'And he took the cup, and gave thanks, and said, Take this, and divide it among yourselves:', 'καὶ δεξάμενος ποτήριον εὐχαριστήσας εἶπεν, Λάβετε τοῦτο καὶ διαμερίσατε εἰς ἑαυτούς·', 'kai dexamenos potērion eucharistēsas eipen, Labete touto kai diamerisate eis heautous;', '"He took the cup" (dexamenos potērion — having received a cup) — this is likely the first cup of the Passover Seder (the cup of sanctification, kiddush), distinct from the cup after supper in v.20. "Gave thanks" (eucharistēsas — having given thanks; from eucharistia, the word from which "Eucharist" derives). "Divide it among yourselves" (diamerisate eis heautous — distribute it among yourselves; diamerizō = to divide through, to distribute portions) — the communal sharing of the cup is emphasized. The Passover Seder traditionally involved four cups of wine; Luke records two (vv.17 and 20), framing the bread-saying. The instruction to share distributes the covenant blessings horizontally among the community, not just vertically from God to individuals.', NULL),
  (18, 'For I say unto you, I will not drink of the fruit of the vine, until the kingdom of God shall come.', 'λέγω γὰρ ὑμῖν, οὐ μὴ πίω ἀπὸ τοῦ γενήματος τῆς ἀμπέλου ἕως οὗ ἡ βασιλεία τοῦ Θεοῦ ἔλθῃ.', 'legō gar humin, ou mē piō apo tou genēmatos tēs ampelou heōs hou hē basileia tou Theou elthē.', '"The fruit of the vine" (tou genēmatos tēs ampelou — the produce of the vine; genēma = that which is born/produced, offspring of the vine) — the traditional Jewish blessing formula over wine. "Until the kingdom of God shall come" (heōs hou hē basileia tou Theou elthē — until the kingdom of God comes) — parallel to v.16''s eschatological horizon. This second vow of abstinence, now regarding the cup specifically, creates a profound tension: Jesus will not drink again until the kingdom arrives in its fullness. The post-resurrection meals (24:30, 41-43; Acts 10:41) partially fulfill this promise, but the ultimate fulfillment awaits the messianic banquet. Each Eucharistic celebration thus stands between the cross and the kingdom.', NULL),
  (19, 'And he took bread, and gave thanks, and brake it, and gave unto them, saying, This is my body which is given for you: this do in remembrance of me.', 'καὶ λαβὼν ἄρτον εὐχαριστήσας ἔκλασεν καὶ ἔδωκεν αὐτοῖς λέγων, Τοῦτό ἐστιν τὸ σῶμά μου τὸ ὑπὲρ ὑμῶν διδόμενον· τοῦτο ποιεῖτε εἰς τὴν ἐμὴν ἀνάμνησιν.', 'kai labōn arton eucharistēsas eklasen kai edōken autois legōn, Touto estin to sōma mou to huper humōn didomenon; touto poieite eis tēn emēn anamnēsin.', '"Took bread" (labōn arton — having taken bread; the unleavened bread of the Passover, matzah). "Gave thanks...brake it...gave" — the four actions (taking, thanking, breaking, giving) become the liturgical pattern of the Eucharist (cf. 24:30; Acts 2:42; 1 Cor 11:23-24). "This is my body" (Touto estin to sōma mou — this is my body) — the words of institution. "Which is given for you" (to huper humōn didomenon — the one being given on behalf of you; present participle: being given, in the very act of being given) — the sacrificial, substitutionary character of Jesus'' death is explicit: his body is given for (huper) others. "This do in remembrance of me" (touto poieite eis tēn emēn anamnēsin — do this for my remembrance; anamnēsis = active recollection, not mere memory but a re-presentation that makes the past event present and effective).', NULL),
  (20, 'Likewise also the cup after supper, saying, This cup is the new testament in my blood, which is shed for you.', 'ὡσαύτως καὶ τὸ ποτήριον μετὰ τὸ δειπνῆσαι, λέγων, Τοῦτο τὸ ποτήριον ἡ καινὴ διαθήκη ἐν τῷ αἵματί μου, τὸ ὑπὲρ ὑμῶν ἐκχυννόμενον.', 'hōsautōs kai to potērion meta to deipnēsai, legōn, Touto to potērion hē kainē diathēkē en tō haimati mou, to huper humōn ekchunnomenon.', '"After supper" (meta to deipnēsai — after the dining; this is the third or fourth cup of the Seder, the "cup of blessing" mentioned by Paul in 1 Cor 10:16). "The new testament in my blood" (hē kainē diathēkē en tō haimati mou — the new covenant in my blood) — the explicit allusion to Jeremiah 31:31-34 is unmistakable: "I will make a new covenant with the house of Israel." The old covenant was inaugurated by blood-sprinkling (Exod 24:8: "Behold the blood of the covenant"); the new covenant is inaugurated by Christ''s blood. "Which is shed for you" (to huper humōn ekchunnomenon — the one being poured out on behalf of you; ekchunnomai = to pour out, the language of sacrificial libation and the pouring out of the soul unto death, Isa 53:12). The cup and its contents become the sign of the new covenant relationship between God and his people.', NULL),
  (21, 'But, behold, the hand of him that betrayeth me is with me on the table.', 'πλὴν ἰδοὺ ἡ χεὶρ τοῦ παραδιδόντός με μετ'' ἐμοῦ ἐπὶ τῆς τραπέζης.', 'plēn idou hē cheir tou paradidontos me met'' emou epi tēs trapezēs.', '"But, behold" (plēn idou — nevertheless, look!) — the jarring adversative: immediately after the most sacred moment of the meal, Jesus reveals the presence of betrayal at the very table. "The hand of him that betrayeth me is with me on the table" (hē cheir tou paradidontos me met'' emou epi tēs trapezēs — the hand of the one handing me over is with me on the table) — the "hand" (cheir) represents agency and action; it is the hand that will guide the arrest party. "With me on the table" — the intimacy of table fellowship makes the betrayal more monstrous. In ancient Near Eastern culture, sharing a meal created a sacred bond; betrayal of a table companion was the deepest violation of trust (cf. Ps 41:9: "mine own familiar friend...which did eat of my bread, hath lifted up his heel against me").', NULL),
  (22, 'And truly the Son of man goeth, as it was determined: but woe unto that man by whom he is betrayed!', 'ὅτι ὁ μὲν Υἱὸς τοῦ ἀνθρώπου κατὰ τὸ ὡρισμένον πορεύεται· πλὴν οὐαὶ τῷ ἀνθρώπῳ ἐκείνῳ δι'' οὗ παραδίδοται.', 'hoti ho men Huios tou anthrōpou kata to hōrismenon poreuetai; plēn ouai tō anthrōpō ekeinō di'' hou paradidotai.', '"As it was determined" (kata to hōrismenon — according to what has been determined, decreed; horizō = to mark out boundaries, to determine; the perfect passive participle: what has been determined by God, a settled divine decree) — the cross is not a tragedy that overtakes Jesus but a divinely ordained plan. "But woe unto that man" (ouai tō anthrōpō ekeinō — woe to that man) — divine sovereignty and human responsibility coexist without resolution: God determined the cross, yet the betrayer bears full moral culpability. The "woe" is not a curse but a lament of judgment. This verse is one of the most compact statements of the mystery of divine sovereignty and human responsibility in all of Scripture.', NULL),
  (23, 'And they began to enquire among themselves, which of them it was that should do this thing.', 'καὶ αὐτοὶ ἤρξαντο συζητεῖν πρὸς ἑαυτοὺς τὸ τίς ἄρα εἴη ἐξ αὐτῶν ὁ τοῦτο μέλλων πράσσειν.', 'kai autoi ērxanto suzētein pros heautous to tis ara eiē ex autōn ho touto mellōn prassein.', '"Began to enquire among themselves" (ērxanto suzētein pros heautous — they began to discuss with one another; suzēteō = to seek together, to debate, to question jointly) "which of them it was" (tis ara eiē ex autōn — who then it might be from among them; the optative eiē expresses uncertainty and speculation). The disciples'' inability to identify the betrayer reveals both the hiddenness of Judas''s treachery and a self-awareness among the Twelve: each apparently considers the possibility of his own failure (cf. Matt 26:22: "Is it I, Lord?"). This self-examination is itself a sign of spiritual health — only the guilty party feels no need to question himself.', NULL),
  (24, 'And there was also a strife among them, which of them should be accounted the greatest.', 'Ἐγένετο δὲ καὶ φιλονεικία ἐν αὐτοῖς, τὸ τίς αὐτῶν δοκεῖ εἶναι μείζων.', 'Egeneto de kai philoneikia en autois, to tis autōn dokei einai meizōn.', '"A strife" (philoneikia — a love of rivalry, contentiousness, competitive ambition; from phileō/to love + neikos/strife; a hapax legomenon in the NT) — the word reveals not merely a disagreement but a deep-seated competitive spirit. "Which of them should be accounted the greatest" (tis autōn dokei einai meizōn — which of them is considered to be greatest) — the timing is staggering: at the very table where Jesus has just instituted the new covenant in his blood and announced his impending betrayal, the disciples argue about rank. Luke places this dispute at the Last Supper rather than on the road (as in Mark 9:34; 10:35-45), intensifying the contrast between Jesus'' self-giving and the disciples'' self-promotion.', NULL),
  (25, 'And he said unto them, The kings of the Gentiles exercise lordship over them; and they that exercise authority upon them are called benefactors.', 'ὁ δὲ εἶπεν αὐτοῖς, Οἱ βασιλεῖς τῶν ἐθνῶν κυριεύουσιν αὐτῶν, καὶ οἱ ἐξουσιάζοντες αὐτῶν εὐεργέται καλοῦνται.', 'ho de eipen autois, Hoi basileis tōn ethnōn kurieuousin autōn, kai hoi exousiazontes autōn euergetai kalountai.', '"The kings of the Gentiles exercise lordship" (Hoi basileis tōn ethnōn kurieuousin autōn — the kings of the nations lord it over them; kurieuō from kurios/lord = to exercise lordship, to dominate) — the Gentile political model is top-down coercive authority. "Called benefactors" (euergetai kalountai — are called benefactors; euergetēs was a formal title given to Hellenistic rulers — Ptolemy III, Ptolemy VII, and others bore the title "Euergetes") — the irony is that rulers who exploit their subjects claim the title of "one who does good." Jesus exposes the hypocrisy of power structures that disguise domination as benevolence. The kingdom of God operates on an inverted principle.', NULL),
  (26, 'But ye shall not be so: but he that is greatest among you, let him be as the younger; and he that is chief, as he that doth serve.', 'ὑμεῖς δὲ οὐχ οὕτως, ἀλλ'' ὁ μείζων ἐν ὑμῖν γινέσθω ὡς ὁ νεώτερος, καὶ ὁ ἡγούμενος ὡς ὁ διακονῶν.', 'humeis de ouch houtōs, all'' ho meizōn en humin ginesthō hōs ho neōteros, kai ho hēgoumenos hōs ho diakonōn.', '"But ye shall not be so" (humeis de ouch houtōs — but you, not thus) — a categorical rejection of the Gentile model for the kingdom community. "The greatest...as the younger" (ho meizōn...hōs ho neōteros — the greater as the younger; in ancient culture, the neōteros/younger had the lowest status and served at table). "He that is chief, as he that doth serve" (ho hēgoumenos hōs ho diakonōn — the leader as the one serving; diakonōn from diakoneō = to serve at table, to wait upon, the root of "deacon"). The inversion is radical: greatness in the kingdom is measured not by how many serve you but by how many you serve. This is not mere humility rhetoric but a structural principle: kingdom leadership is servant leadership.', NULL),
  (27, 'For whether is greater, he that sitteth at meat, or he that serveth? is not he that sitteth at meat? but I am among you as he that serveth.', 'τίς γὰρ μείζων, ὁ ἀνακείμενος ἢ ὁ διακονῶν; οὐχὶ ὁ ἀνακείμενος; ἐγὼ δὲ ἐν μέσῳ ὑμῶν εἰμι ὡς ὁ διακονῶν.', 'tis gar meizōn, ho anakeimenos ē ho diakonōn? ouchi ho anakeimenos? egō de en mesō humōn eimi hōs ho diakonōn.', '"Whether is greater, he that sitteth at meat, or he that serveth?" (tis gar meizōn, ho anakeimenos ē ho diakonōn — for who is greater, the one reclining or the one serving?) — a rhetorical question with an obvious cultural answer: the guest reclining at table holds higher status than the servant waiting on him. "Is not he that sitteth at meat?" (ouchi ho anakeimenos — is it not the one reclining?) — Jesus acknowledges the conventional answer. "But I am among you as he that serveth" (egō de en mesō humōn eimi hōs ho diakonōn — but I in the midst of you am as the one serving) — Jesus, the Lord and Master, takes the servant''s position. The statement is programmatic for Lucan Christology: the Son of Man came "not to be ministered unto, but to minister" (Mark 10:45). John 13:1-17 dramatizes this same principle in the foot-washing.', NULL),
  (28, 'Ye are they which have continued with me in my temptations.', 'ὑμεῖς δέ ἐστε οἱ διαμεμενηκότες μετ'' ἐμοῦ ἐν τοῖς πειρασμοῖς μου·', 'humeis de este hoi diamemenēkotes met'' emou en tois peirasmois mou;', '"Ye are they which have continued with me" (humeis...hoi diamemenēkotes met'' emou — you are the ones who have remained with me throughout; diamenō = to remain through, to persist through; the perfect participle indicates a settled state: they have stayed and are still staying). "In my temptations" (en tois peirasmois mou — in my trials/testings; peirasmos can mean temptation or trial; here the broader sense of trials throughout Jesus'' ministry). Despite their failings — their ambition (v.24), their coming failure (v.34, 54-62), their flight — Jesus commends their perseverance through the trials of his public ministry. The commendation is generous and forward-looking: despite what is about to happen, their fundamental loyalty is acknowledged.', NULL),
  (29, 'And I appoint unto you a kingdom, as my Father hath appointed unto me;', 'κἀγὼ διατίθεμαι ὑμῖν καθὼς διέθετό μοι ὁ Πατήρ μου βασιλείαν,', 'kagō diatithemai humin kathōs dietheto moi ho Patēr mou basileian,', '"I appoint unto you a kingdom" (diatithemai humin...basileian — I covenant to you a kingdom; diatithemai from diatithēmi = to arrange, to covenant, to bequeath by testament; the same root as diathēkē/covenant in v.20) — Jesus uses covenant language: he is bequeathing to his apostles a share in his royal authority. "As my Father hath appointed unto me" (kathōs dietheto moi ho Patēr mou — just as my Father covenanted to me) — the chain of covenantal appointment runs from the Father to the Son to the apostles. The kingdom is not seized by ambition but received by covenant grant. The verb diatithemai creates a verbal echo with "new testament" (diathēkē) in v.20: the new covenant includes not only forgiveness of sins but also the bestowal of kingdom authority upon Christ''s faithful servants.', NULL),
  (30, 'That ye may eat and drink at my table in my kingdom, and sit on thrones judging the twelve tribes of Israel.', 'ἵνα ἔσθητε καὶ πίνητε ἐπὶ τῆς τραπέζης μου ἐν τῇ βασιλείᾳ μου, καὶ καθήσεσθε ἐπὶ θρόνων τὰς δώδεκα φυλὰς κρίνοντες τοῦ Ἰσραήλ.', 'hina esthēte kai pinēte epi tēs trapezēs mou en tē basileia mou, kai kathēsesthe epi thronōn tas dōdeka phulas krinontes tou Israēl.', '"Eat and drink at my table in my kingdom" (esthēte kai pinēte epi tēs trapezēs mou en tē basileia mou — that you may eat and drink at my table in my kingdom) — the messianic banquet, the eschatological fulfillment of the Passover meal they are sharing. "Sit on thrones judging the twelve tribes of Israel" (kathēsesthe epi thronōn...krinontes — you will sit on thrones judging) — the apostles receive judicial-administrative authority over restored Israel (cf. Matt 19:28; Dan 7:22; Rev 20:4). "Judging" (krinontes) carries the OT sense of ruling and governing as well as judicial decision (cf. the Book of Judges). The promise transforms the disciples'' petty argument about status into a vision of genuine eschatological authority — an authority that comes not through self-promotion but through faithful perseverance in suffering.', NULL),
  (31, 'And the Lord said, Simon, Simon, behold, Satan hath desired to have you, that he may sift you as wheat:', 'Σίμων Σίμων, ἰδοὺ ὁ Σατανᾶς ἐξῃτήσατο ὑμᾶς τοῦ σινιάσαι ὡς τὸν σῖτον·', 'Simōn Simōn, idou ho Satanas exētēsato humas tou siniasai hōs ton siton;', '"Simon, Simon" (Simōn Simōn — the doubled name signals urgency and personal gravity; cf. "Martha, Martha" in 10:41; "Saul, Saul" in Acts 9:4). "Satan hath desired to have you" (ho Satanas exētēsato humas — Satan has demanded you [plural]; exaiteō = to demand, to claim for oneself, to ask for with authority; the word implies Satan appeared before God with a demand, recalling Job 1:6-12). The "you" (humas) is plural — Satan has demanded all the disciples, not just Peter. "Sift you as wheat" (siniasai hōs ton siton — to sift like wheat; siniazō = to shake in a sieve, separating grain from chaff) — the metaphor implies violent shaking that tests what is genuine. Satan''s intention is destruction; God permits the sifting for purification.', NULL),
  (32, 'But I have prayed for thee, that thy faith fail not: and when thou art converted, strengthen thy brethren.', 'ἐγὼ δὲ ἐδεήθην περὶ σοῦ ἵνα μὴ ἐκλίπῃ ἡ πίστις σου· καὶ σύ ποτε ἐπιστρέψας στήρισον τοὺς ἀδελφούς σου.', 'egō de edeēthēn peri sou hina mē eklipē hē pistis sou; kai su pote epistrepsas stērison tous adelphous sou.', '"But I have prayed for thee" (egō de edeēthēn peri sou — but I, I have made supplication concerning you [singular]; the emphatic egō and the shift from plural humas to singular sou is pointed: Satan demanded all, but Jesus prays specifically for Peter). "That thy faith fail not" (hina mē eklipē hē pistis sou — that your faith may not utterly fail; ekleipō = to fail completely, to be totally eclipsed) — the prayer is not that Peter will not fall (he will deny three times) but that his faith will survive the fall and be recoverable. "When thou art converted" (epistrepsas — having turned back, having returned; the word implies Peter will indeed fall away and then return). "Strengthen thy brethren" (stērison tous adelphous sou — establish, make firm your brothers) — Peter''s restored failure becomes the very qualification for strengthening others. His pastoral authority comes through brokenness, not despite it.', NULL),
  (33, 'And he said unto him, Lord, I am ready to go with thee, both into prison, and to death.', 'ὁ δὲ εἶπεν αὐτῷ, Κύριε, μετὰ σοῦ ἕτοιμός εἰμι καὶ εἰς φυλακὴν καὶ εἰς θάνατον πορεύεσθαι.', 'ho de eipen autō, Kurie, meta sou hetoimos eimi kai eis phulakēn kai eis thanaton poreuesthai.', '"Lord, I am ready" (Kurie...hetoimos eimi — Lord, I am prepared) — Peter''s response is sincere but overconfident; he assesses his own courage without accounting for the sifting Satan has demanded. "Both into prison, and to death" (kai eis phulakēn kai eis thanaton — both to prison and to death) — Peter pledges the ultimate loyalty. The irony is that Peter will indeed eventually go to prison (Acts 5:18; 12:3-4) and to death (tradition records his crucifixion under Nero), but not this night. This night, he will deny three times. The gap between Peter''s self-assessment and his actual performance under pressure is one of the most psychologically realistic portraits in the Gospels.', NULL),
  (34, 'And he said, I tell thee, Peter, the cock shall not crow this day, before that thou shalt thrice deny that thou knowest me.', 'ὁ δὲ εἶπεν, Λέγω σοι, Πέτρε, οὐ φωνήσει σήμερον ἀλέκτωρ ἕως τρίς με ἀπαρνήσῃ εἰδέναι.', 'ho de eipen, Legō soi, Petre, ou phōnēsei sēmeron alektōr heōs tris me aparnēsē eidenai.', '"I tell thee, Peter" (Legō soi, Petre — I say to you, Peter; Jesus uses his apostolic name, not "Simon" as in v.31, perhaps because the prediction concerns his role as the Rock) — the solemn first-person declaration. "The cock shall not crow this day" (ou phōnēsei sēmeron alektōr — a rooster will not sound today; the cockcrow traditionally marked the early morning hours, approximately 3 AM). "Before that thou shalt thrice deny that thou knowest me" (heōs tris me aparnēsē eidenai — until three times you deny knowing me; aparneomai = to deny utterly, to disown; the addition of eidenai/to know specifies that Peter will deny even acquaintance with Jesus). The prediction is precise: three denials before a specific time marker, all fulfilled in vv.54-62.', NULL),
  (35, 'And he said unto them, When I sent you without purse, and scrip, and shoes, lacked ye any thing? And they said, Nothing.', 'Καὶ εἶπεν αὐτοῖς, Ὅτε ἀπέστειλα ὑμᾶς ἄτερ βαλλαντίου καὶ πήρας καὶ ὑποδημάτων, μή τινος ὑστερήσατε; οἱ δὲ εἶπαν, Οὐθενός.', 'Kai eipen autois, Hote apesteila humas ater ballantiou kai pēras kai hupodēmatōn, mē tinos husterēsate? hoi de eipan, Outhenos.', '"When I sent you without purse, and scrip, and shoes" (Hote apesteila humas ater ballantiou kai pēras kai hupodēmatōn — when I sent you without money bag and travel bag and sandals) — Jesus refers back to the mission instructions of 10:4 (and 9:3), where the Seventy were sent out in radical dependence on God''s provision through hospitable reception. "Lacked ye any thing?" (mē tinos husterēsate — did you lack anything?) — the expected negative answer: they lacked nothing. "Nothing" (Outhenos — not a thing) — the mission of proclamation was fully provisioned by God''s care through the community''s hospitality. This reminiscence establishes the baseline: the former mission conditions were characterized by divine sufficiency.', NULL),
  (36, 'Then said he unto them, But now, he that hath a purse, let him take it, and likewise his scrip: and he that hath no sword, let him sell his garment, and buy one.', 'εἶπεν δὲ αὐτοῖς, Ἀλλὰ νῦν ὁ ἔχων βαλλάντιον ἀράτω, ὁμοίως καὶ πήραν, καὶ ὁ μὴ ἔχων πωλησάτω τὸ ἱμάτιον αὐτοῦ καὶ ἀγορασάτω μάχαιραν.', 'eipen de autois, Alla nun ho echōn ballantion aratō, homoiōs kai pēran, kai ho mē echōn pōlēsatō to himation autou kai agorasatō machairan.', '"But now" (Alla nun — but now; the strong adversative signals a fundamental change in circumstances) — the conditions of the earlier mission no longer apply. "He that hath a purse, let him take it" — self-provisioning is now required because the welcoming reception the disciples previously enjoyed will be replaced by hostility. "He that hath no sword, let him sell his garment, and buy one" (pōlēsatō to himation...agorasatō machairan — let him sell his cloak and buy a sword) — the saying is widely debated. It almost certainly does not mean Jesus is arming the disciples for violent resistance (he will rebuke sword-use in v.51). Rather, the sword symbolizes the coming crisis: the time of peaceful mission is over, the hour of confrontation and danger has arrived. Jesus speaks the language of crisis, not military strategy.', NULL),
  (37, 'For I say unto you, that this that is written must yet be accomplished in me, And he was reckoned among the transgressors: for the things concerning me have an end.', 'λέγω γὰρ ὑμῖν ὅτι ἔτι τοῦτο τὸ γεγραμμένον δεῖ τελεσθῆναι ἐν ἐμοί, τό, Καὶ μετὰ ἀνόμων ἐλογίσθη· καὶ γὰρ τὸ περὶ ἐμοῦ τέλος ἔχει.', 'legō gar humin hoti eti touto to gegrammenon dei telesthēnai en emoi, to, Kai meta anomōn elogisthē; kai gar to peri emou telos echei.', '"This that is written must yet be accomplished in me" (touto to gegrammenon dei telesthēnai en emoi — this written word must be fulfilled in me; dei = divine necessity; telesthēnai = be completed, reach its telos/goal) — the Scripture that must be fulfilled is Isaiah 53:12. "He was reckoned among the transgressors" (meta anomōn elogisthē — with lawless ones he was counted; logizomai = to reckon, to number, an accounting term; anomos = lawless, transgressor) — Jesus will be crucified between two criminals (23:33), literally numbered with transgressors. "The things concerning me have an end" (to peri emou telos echei — the things concerning me are reaching their end/goal; telos can mean both ending and purpose) — Jesus'' life is reaching its divinely scripted culmination. This is the theological reason for the "sword" saying: Jesus is about to be treated as a criminal, and association with him will be dangerous.', NULL),
  (38, 'And they said, Lord, behold, here are two swords. And he said unto them, It is enough.', 'οἱ δὲ εἶπαν, Κύριε, ἰδοὺ μάχαιραι ὧδε δύο. ὁ δὲ εἶπεν αὐτοῖς, Ἱκανόν ἐστιν.', 'hoi de eipan, Kurie, idou machairai hōde duo. ho de eipen autois, Hikanon estin.', '"Lord, behold, here are two swords" (Kurie, idou machairai hōde duo — Lord, look, two swords here) — the disciples take the sword-saying literally and produce two actual swords (machairai — short swords or large knives, possibly carried for protection on journeys or for slaughtering the Passover lamb). "It is enough" (Hikanon estin — it is sufficient, enough) — Jesus''s response is widely interpreted as either (1) ironic dismissal: "Enough of this talk!" — ending a conversation the disciples have misunderstood; or (2) a statement that two swords are sufficient to fulfill Isaiah 53:12 — enough to get Jesus classified as a transgressor. The latter interpretation aligns with v.37: the swords serve the prophetic script, not a military strategy. Two swords against a Roman-backed arrest party would be absurd as armament but sufficient as evidence of criminal association.', NULL),
  (39, 'And he came out, and went, as he was wont, to the mount of Olives; and his disciples also followed him.', 'Καὶ ἐξελθὼν ἐπορεύθη κατὰ τὸ ἔθος εἰς τὸ ὄρος τῶν Ἐλαιῶν· ἠκολούθησαν δὲ αὐτῷ καὶ οἱ μαθηταί.', 'Kai exelthōn eporeuthē kata to ethos eis to Oros tōn Elaiōn; ēkolouthēsan de autō kai hoi mathētai.', '"As he was wont" (kata to ethos — according to his custom/habit; ethos = custom, established practice) — Jesus goes to the Mount of Olives as he did each evening (21:37). This customary pattern is what made Judas''s betrayal effective: he knew where Jesus would be (John 18:2). "The mount of Olives" (to Oros tōn Elaiōn — the Mountain of Olives, directly east of the Temple across the Kidron Valley) — the traditional location of Gethsemane ("oil press"), though Luke does not use the name Gethsemane. "His disciples also followed him" (ēkolouthēsan de autō kai hoi mathētai — the disciples also followed him) — Luke does not restrict the group to Peter, James, and John as Mark does (Mark 14:33); all the disciples accompany Jesus to the place of prayer.', NULL),
  (40, 'And when he was at the place, he said unto them, Pray that ye enter not into temptation.', 'γενόμενος δὲ ἐπὶ τοῦ τόπου εἶπεν αὐτοῖς, Προσεύχεσθε μὴ εἰσελθεῖν εἰς πειρασμόν.', 'genomenos de epi tou topou eipen autois, Proseuchesthe mē eiselthein eis peirasmon.', '"When he was at the place" (genomenos epi tou topou — having arrived at the place; topos = the place, with the definite article suggesting a known, specific location). "Pray that ye enter not into temptation" (Proseuchesthe mē eiselthein eis peirasmon — pray not to enter into testing/trial) — the command frames the Gethsemane scene with prayer as the antidote to spiritual collapse. "Temptation" (peirasmon — testing, trial; the same word used in the Lord''s Prayer, 11:4: "lead us not into temptation") — the peirasmos here is the supreme test of the Passion: will the disciples stand firm or fall away? Jesus repeats this command in v.46, creating an inclusio (literary bracket) around the entire prayer scene. The disciples'' failure to pray results in their failure to stand.', NULL),
  (41, 'And he was withdrawn from them about a stone''s cast, and kneeled down, and prayed,', 'καὶ αὐτὸς ἀπεσπάσθη ἀπ'' αὐτῶν ὡσεὶ λίθου βολήν, καὶ θεὶς τὰ γόνατα προσηύχετο', 'kai autos apespasthē ap'' autōn hōsei lithou bolēn, kai theis ta gonata prosēucheto', '"Withdrawn from them" (apespasthē — was torn away, was pulled apart from; apaspaō = to draw away, a word suggesting reluctant separation, almost as if pulled by an invisible force) — the passive voice may suggest divine compulsion: God drew Jesus apart for this agonizing prayer. "About a stone''s cast" (hōsei lithou bolēn — about the throw of a stone; approximately 50-100 feet) — close enough to be seen, far enough for private prayer. "Kneeled down" (theis ta gonata — having placed his knees; a posture of intense supplication; Jewish prayer was normally standing with upraised hands; kneeling indicated exceptional urgency and distress, cf. Acts 7:60; 9:40; 20:36). "Prayed" (prosēucheto — was praying; the imperfect tense: continued praying, sustained prayer).', NULL),
  (42, 'Saying, Father, if thou be willing, remove this cup from me: nevertheless not my will, but thine, be done.', 'λέγων, Πάτερ, εἰ βούλει παρένεγκε τοῦτο τὸ ποτήριον ἀπ'' ἐμοῦ· πλὴν μὴ τὸ θέλημά μου ἀλλὰ τὸ σὸν γινέσθω.', 'legōn, Pater, ei boulei parenenke touto to potērion ap'' emou; plēn mē to thelēma mou alla to son ginesthō.', '"Father" (Pater — Father; the intimate address to God that characterizes all of Jesus'' prayers in Luke except the cry of dereliction). "If thou be willing" (ei boulei — if you are willing; boulomai = to will, to purpose, a deliberative will) — the conditional clause acknowledges the Father''s sovereign freedom. "Remove this cup from me" (parenenke touto to potērion — carry away this cup; parapherō = to carry aside, to remove; the cup is the cup of divine wrath and the agony of the cross, cf. Isa 51:17, 22; Jer 25:15-16) — Jesus does not desire suffering for its own sake. "Nevertheless not my will, but thine, be done" (plēn mē to thelēma mou alla to son ginesthō — but not my will but yours be done) — the supreme act of human submission to divine purpose. This prayer is the model for all Christian prayer: honest expression of desire submitted to sovereign will.', NULL),
  (43, 'And there appeared an angel unto him from heaven, strengthening him.', 'ὤφθη δὲ αὐτῷ ἄγγελος ἀπ'' οὐρανοῦ ἐνισχύων αὐτόν.', 'ōphthē de autō angelos ap'' ouranou enischuōn auton.', '"There appeared an angel unto him from heaven" (ōphthē autō angelos ap'' ouranou — an angel from heaven appeared to him; ōphthē = appeared, the word used for divine appearances/theophanies) — this detail is unique to Luke and is part of the so-called "longer reading" of vv.43-44 (absent from some important manuscripts but included in the majority). "Strengthening him" (enischuōn auton — strengthening him, empowering him; enischuō = to make strong in) — the angel does not remove the cup but provides strength to drink it. The scene recalls 1 Kings 19:5-8, where an angel strengthened the exhausted Elijah. The theological significance is profound: even the incarnate Son required supernatural strengthening to face the cross, demonstrating the genuine humanity of his suffering and the reality of the anguish the cross entailed.', NULL),
  (44, 'And being in an agony he prayed more earnestly: and his sweat was as it were great drops of blood falling down to the ground.', 'καὶ γενόμενος ἐν ἀγωνίᾳ ἐκτενέστερον προσηύχετο· καὶ ἐγένετο ὁ ἱδρὼς αὐτοῦ ὡσεὶ θρόμβοι αἵματος καταβαίνοντες ἐπὶ τὴν γῆν.', 'kai genomenos en agōnia ektenesteron prosēucheto; kai egeneto ho hidrōs autou hōsei thromboi haimatos katabainontes epi tēn gēn.', '"Being in an agony" (genomenos en agōnia — being in agony; agōnia from agōn/contest = the intense struggle of an athlete, the anguish of extreme exertion; the word appears only here in the NT). "Prayed more earnestly" (ektenesteron prosēucheto — prayed more intensely; the comparative adverb: with greater stretching out, greater extension of effort; ektenēs = stretched out, intense). "His sweat was as it were great drops of blood" (ho hidrōs autou hōsei thromboi haimatos — his sweat became like clots/drops of blood; thromboi = clots, thick drops; a medical term used by Aristotle and Theophrastus) — the "as it were" (hōsei) may indicate comparison: sweat falling like drops of blood (in quantity and heaviness), or it may describe hematidrosis, a rare medical condition where extreme stress causes capillaries to rupture into sweat glands, producing bloody sweat. Luke the physician uses precise medical terminology.', NULL),
  (45, 'And when he rose up from prayer, and was come to his disciples, he found them sleeping for sorrow.', 'καὶ ἀναστὰς ἀπὸ τῆς προσευχῆς ἐλθὼν πρὸς τοὺς μαθητὰς εὗρεν κοιμωμένους αὐτοὺς ἀπὸ τῆς λύπης,', 'kai anastas apo tēs proseuchēs elthōn pros tous mathētas heuren koimōmenous autous apo tēs lupēs,', '"Rose up from prayer" (anastas apo tēs proseuchēs — having risen from the prayer) — the prayer is complete; the decision is made; Jesus rises strengthened. "Found them sleeping for sorrow" (heuren koimōmenous autous apo tēs lupēs — found them sleeping from grief; koimaomai = to sleep; lupē = grief, sorrow) — Luke alone adds "for sorrow" (apo tēs lupēs), providing a compassionate explanation for the disciples'' failure to stay awake. They are not indifferent; they are overwhelmed with grief. Mark 14:37 records Jesus'' rebuke of Peter by name; Luke omits this, softening the portrayal of the disciples. The sorrow that causes sleep is itself a form of the temptation Jesus warned against: the overwhelming pressure that leads to spiritual collapse.', NULL),
  (46, 'And said unto them, Why sleep ye? rise and pray, lest ye enter into temptation.', 'καὶ εἶπεν αὐτοῖς, Τί καθεύδετε; ἀναστάντες προσεύχεσθε, ἵνα μὴ εἰσέλθητε εἰς πειρασμόν.', 'kai eipen autois, Ti katheudete? anastantes proseuchesthe, hina mē eiselthēte eis peirasmon.', '"Why sleep ye?" (Ti katheudete — why are you sleeping?) — the question is both practical and spiritual. "Rise and pray, lest ye enter into temptation" (anastantes proseuchesthe, hina mē eiselthēte eis peirasmon — having risen, pray, that you may not enter into trial) — the repetition of v.40''s command creates a literary bracket: the Gethsemane scene is framed by the imperative to pray against temptation. Luke condenses Mark''s three prayer sessions into one, maintaining the essential point: the disciples'' prayerlessness leaves them defenseless against the coming crisis. Within hours, Peter will deny Jesus, confirming that the failure to pray resulted in entry into the very peirasmos Jesus warned about.', NULL),
  (47, 'And while he yet spake, behold a multitude, and he that was called Judas, one of the twelve, went before them, and drew near unto Jesus to kiss him.', 'Ἔτι αὐτοῦ λαλοῦντος ἰδοὺ ὄχλος, καὶ ὁ λεγόμενος Ἰούδας εἷς τῶν δώδεκα προήρχετο αὐτοὺς καὶ ἤγγισεν τῷ Ἰησοῦ φιλῆσαι αὐτόν.', 'Eti autou lalountos idou ochlos, kai ho legomenos Ioudas heis tōn dōdeka proērcheto autous kai ēngisen tō Iēsou philēsai auton.', '"While he yet spake" (Eti autou lalountos — while he was still speaking; a genitive absolute indicating interruption) — the arrest comes mid-sentence, before the prayer exhortation can take effect. "A multitude" (ochlos — a crowd; Luke does not specify the composition, though John 18:3 identifies Roman soldiers and Temple police). "He that was called Judas, one of the twelve" (ho legomenos Ioudas heis tōn dōdeka — the one called Judas, one of the Twelve) — the repeated identification of Judas as "one of the Twelve" is devastating in its emphasis. "Drew near...to kiss him" (ēngisen...philēsai auton — approached to kiss him; phileō = to kiss as a greeting, a sign of affection and respect between teacher and disciple) — the kiss, a gesture of intimacy, is perverted into a signal for arrest.', NULL),
  (48, 'But Jesus said unto him, Judas, betrayest thou the Son of man with a kiss?', 'Ἰησοῦς δὲ εἶπεν αὐτῷ, Ἰούδα, φιλήματι τὸν Υἱὸν τοῦ ἀνθρώπου παραδίδως;', 'Iēsous de eipen autō, Iouda, philēmati ton Huion tou anthrōpou paradidōs?', '"Judas, betrayest thou the Son of man with a kiss?" (Iouda, philēmati ton Huion tou anthrōpou paradidōs — Judas, with a kiss you are handing over the Son of Man?) — the question exposes the obscenity of the act: the instrument of betrayal is a symbol of love. "With a kiss" (philēmati — by a kiss; the dative of instrument) — the means is as important as the act; it is the corruption of the most intimate gesture. Jesus names the betrayer, names the act, and names the victim ("the Son of Man" — his messianic title from Daniel 7:13). The question is not requesting information but confronting Judas with the full moral weight of what he is doing. There is still, in the question, an implicit invitation to reconsider.', NULL),
  (49, 'When they which were about him saw what would follow, they said unto him, Lord, shall we smite with the sword?', 'ἰδόντες δὲ οἱ περὶ αὐτὸν τὸ ἐσόμενον εἶπαν, Κύριε, εἰ πατάξομεν ἐν μαχαίρῃ;', 'idontes de hoi peri auton to esomenon eipan, Kurie, ei pataxomen en machairē?', '"They which were about him" (hoi peri auton — those around him, his companions) "saw what would follow" (to esomenon — the thing about to happen; they perceived the imminent arrest). "Lord, shall we smite with the sword?" (Kurie, ei pataxomen en machairē — Lord, shall we strike with a sword?) — the disciples recall the two swords of v.38 and ask permission for armed resistance. The question is grammatically a conditional: "if we should strike" — revealing uncertainty about whether violence is appropriate. Only Luke records this question, showing the disciples'' willingness to fight but also their deference to Jesus'' authority. The answer comes indirectly: one disciple strikes before receiving permission (v.50), and Jesus immediately countermands the violence (v.51).', NULL),
  (50, 'And one of them smote the servant of the high priest, and cut off his right ear.', 'καὶ ἐπάταξεν εἷς τις ἐξ αὐτῶν τοῦ ἀρχιερέως τὸν δοῦλον καὶ ἀφεῖλεν τὸ οὖς αὐτοῦ τὸ δεξιόν.', 'kai epataxen heis tis ex autōn tou archiereōs ton doulon kai apheilen to ous autou to dexion.', '"One of them" (heis tis ex autōn — a certain one from among them; Luke does not identify the swordsman; John 18:10 names him as Peter and the servant as Malchus). "Smote the servant of the high priest" (epataxen tou archiereōs ton doulon — struck the high priest''s slave; patassō = to strike, to hit) — the high priest''s personal servant would have been a prominent member of the arrest party. "Cut off his right ear" (apheilen to ous autou to dexion — removed his right ear; the detail "right" is specific to Luke and John) — the blow was likely aimed at the head; the ear was severed by a glancing or deflected strike. Luke the physician notes the specific ear, characteristic of his medical precision.', NULL),
  (51, 'And Jesus answered and said, Suffer ye thus far. And he touched his ear, and healed him.', 'ἀποκριθεὶς δὲ ὁ Ἰησοῦς εἶπεν, Ἐᾶτε ἕως τούτου· καὶ ἁψάμενος τοῦ ὠτίου ἰάσατο αὐτόν.', 'apokritheis de ho Iēsous eipen, Eate heōs toutou; kai hapsamenos tou ōtiou iasato auton.', '"Suffer ye thus far" (Eate heōs toutou — permit this, stop at this point; allow things to proceed; or: enough of this!) — the command halts all further violence. "He touched his ear, and healed him" (hapsamenos tou ōtiou iasato auton — having touched his ear, he healed him; iaomai = to heal, to cure) — this healing is unique to Luke and is the last miracle recorded in Jesus'' public ministry. The detail is extraordinary: Jesus heals the wound inflicted by his own disciple upon his enemy. In the very moment of his arrest, Jesus performs an act of compassionate healing for a member of the party seizing him. The act embodies his own teaching: "Love your enemies, do good to them which hate you" (6:27).', NULL),
  (52, 'Then Jesus said unto the chief priests, and captains of the temple, and the elders, which were come to him, Be ye come out, as against a thief, with swords and staves?', 'εἶπεν δὲ Ἰησοῦς πρὸς τοὺς παραγενομένους ἐπ'' αὐτὸν ἀρχιερεῖς καὶ στρατηγοὺς τοῦ ἱεροῦ καὶ πρεσβυτέρους, Ὡς ἐπὶ λῃστὴν ἐξήλθατε μετὰ μαχαιρῶν καὶ ξύλων;', 'eipen de Iēsous pros tous paragenomenous ep'' auton archiereis kai stratēgous tou hierou kai presbuterous, Hōs epi lēstēn exēlthate meta machairōn kai xulōn?', '"The chief priests, and captains of the temple, and the elders" (archiereis kai stratēgous tou hierou kai presbuterous) — Luke alone records the presence of these senior leaders at the arrest itself, making the official nature of the action explicit. "As against a thief" (Hōs epi lēstēn — as against a brigand, a robber, an insurrectionist; lēstēs is the word Josephus uses for revolutionary bandits and zealot fighters) — Jesus points out the absurdity and malice of armed arrest for someone who taught daily in the Temple. "With swords and staves" (meta machairōn kai xulōn — with swords and clubs) — the military force is disproportionate, treating a teacher as an armed insurrectionist. The irony: they will crucify him between actual lēstai (23:33).', NULL),
  (53, 'When I was daily with you in the temple, ye stretched forth no hands against me: but this is your hour, and the power of darkness.', 'καθ'' ἡμέραν ὄντος μου μεθ'' ὑμῶν ἐν τῷ ἱερῷ οὐκ ἐξετείνατε τὰς χεῖρας ἐπ'' ἐμέ· ἀλλ'' αὕτη ἐστὶν ὑμῶν ἡ ὥρα καὶ ἡ ἐξουσία τοῦ σκότους.', 'kath'' hēmeran ontos mou meth'' humōn en tō hierō ouk exeteinate tas cheiras ep'' eme; all'' hautē estin humōn hē hōra kai hē exousia tou skotous.', '"When I was daily with you in the temple" (kath'' hēmeran ontos mou meth'' humōn en tō hierō — day by day while I was with you in the Temple) — Jesus could have been arrested publicly at any time; the nighttime, secretive arrest reveals its true character. "Ye stretched forth no hands against me" (ouk exeteinate tas cheiras ep'' eme — you did not extend your hands against me) — their public restraint and nocturnal aggression expose their fear of the people and their moral cowardice. "This is your hour, and the power of darkness" (hautē estin humōn hē hōra kai hē exousia tou skotous — this is your hour and the authority of the darkness) — uniquely Lucan, profoundly theological. "Your hour" (humōn hē hōra) is the allotted time given to human evil; "the power of darkness" (hē exousia tou skotous = the authority of the darkness) — behind the human conspirators stands a cosmic power. Satan, who entered Judas (v.3), animates the entire arrest.', NULL),
  (54, 'Then took they him, and led him, and brought him into the high priest''s house. And Peter followed afar off.', 'Συλλαβόντες δὲ αὐτὸν ἤγαγον καὶ εἰσήγαγον εἰς τὴν οἰκίαν τοῦ ἀρχιερέως· ὁ δὲ Πέτρος ἠκολούθει μακρόθεν.', 'Sullabontes de auton ēgagon kai eisēgagon eis tēn oikian tou archiereōs; ho de Petros ēkolouthei makrothen.', '"Took they him, and led him" (Sullabontes auton ēgagon — having seized him, they led him; sullambanō = to take together, to arrest) — the arrest is executed. "Into the high priest''s house" (eis tēn oikian tou archiereōs — into the house of the high priest; Luke does not name the high priest here; John 18:13 identifies the first stop as Annas, then transfer to Caiaphas). "Peter followed afar off" (ho de Petros ēkolouthei makrothen — Peter was following from a distance; the imperfect tense: he kept following, at a distance) — Peter is neither fully loyal (he is "afar off") nor fully faithless (he still follows). The "distance" is both physical and spiritual: close enough to observe, far enough to deny. His journey from following "afar off" to the triple denial is a gradual descent.', NULL),
  (55, 'And when they had kindled a fire in the midst of the hall, and were set down together, Peter sat down among them.', 'περιαψάντων δὲ πῦρ ἐν μέσῳ τῆς αὐλῆς καὶ συγκαθισάντων ἐκάθητο ὁ Πέτρος μέσος αὐτῶν.', 'periapsantōn de pur en mesō tēs aulēs kai sunkathisantōn ekathēto ho Petros mesos autōn.', '"Kindled a fire in the midst of the hall" (periapsantōn pur en mesō tēs aulēs — having kindled a fire in the middle of the courtyard; aulē = courtyard, the open central court of the high priest''s residence). "Peter sat down among them" (ekathēto ho Petros mesos autōn — Peter was sitting in the middle of them) — the fire provides warmth on a cool April night but also illumination that will expose Peter to recognition. "Among them" (mesos autōn — in the midst of them) — Peter has placed himself in the most dangerous possible position: surrounded by the enemies of Jesus, seeking the warmth of their fire, exposed to their questions. The fire becomes the stage for his denial.', NULL),
  (56, 'But a certain maid beheld him as he sat by the fire, and earnestly looked upon him, and said, This man was also with him.', 'ἰδοῦσα δὲ αὐτὸν παιδίσκη τις καθήμενον πρὸς τὸ φῶς καὶ ἀτενίσασα αὐτῷ εἶπεν, Καὶ οὗτος σὺν αὐτῷ ἦν.', 'idousa de auton paidiskē tis kathēmenon pros to phōs kai atenisasa autō eipen, Kai houtos sun autō ēn.', '"A certain maid" (paidiskē tis — a certain servant girl; the most socially insignificant accuser — Peter, who pledged to follow Jesus to prison and death, is undone by a slave girl''s observation). "Beheld him as he sat by the fire" (idousa auton kathēmenon pros to phōs — seeing him sitting by the light; the fire''s light reveals him) — light (phōs) here works ironically: it exposes Peter physically while he sits in spiritual darkness. "Earnestly looked upon him" (atenisasa autō — having gazed intently at him; atenizō = to fix one''s gaze upon, to stare; a Lucan favorite, used for close scrutiny). "This man was also with him" (Kai houtos sun autō ēn — this one also was with him) — the accusation is simple: association with Jesus.', NULL),
  (57, 'And he denied him, saying, Woman, I know him not.', 'ὁ δὲ ἠρνήσατο λέγων, Οὐκ οἶδα αὐτόν, γύναι.', 'ho de ērnēsato legōn, Ouk oida auton, gunai.', '"He denied him" (ērnēsato — he denied; arneomai = to deny, to disown, to refuse to acknowledge) — the first denial. "I know him not" (Ouk oida auton — I do not know him) — Peter denies even acquaintance, exactly as Jesus predicted (v.34: "thrice deny that thou knowest me"). "Woman" (gunai — woman; a polite address, not disrespectful in Greek, but dismissive in context) — Peter addresses the slave girl with apparent indifference, as if the question is beneath notice. The denial is not elaborate; it is flat, simple, and devastating. The man who said "I am ready to go with thee...to death" (v.33) cannot even acknowledge knowing Jesus when questioned by a servant.', NULL),
  (58, 'And after a little while another saw him, and said, Thou art also of them. And Peter said, Man, I am not.', 'καὶ μετὰ βραχὺ ἕτερος ἰδὼν αὐτὸν ἔφη, Καὶ σὺ ἐξ αὐτῶν εἶ. ὁ δὲ Πέτρος ἔφη, Ἄνθρωπε, οὐκ εἰμί.', 'kai meta brachu heteros idōn auton ephē, Kai su ex autōn ei. ho de Petros ephē, Anthrōpe, ouk eimi.', '"After a little while" (meta brachu — after a short time) — the second denial comes in quick succession. "Another saw him" (heteros idōn auton — another person having seen him; heteros = another of a different kind, a different individual). "Thou art also of them" (Kai su ex autōn ei — you too are from among them) — the accusation broadens: not just association with Jesus but membership in his group. "Man, I am not" (Anthrōpe, ouk eimi — Man, I am not) — the second denial; Anthrōpe (Man, Sir) mirrors gunai (Woman) of the first denial. "I am not" (ouk eimi) stands in stark contrast to Jesus'' "I am" (egō eimi) before the Sanhedrin and in the Gospel of John. Peter''s identity is dissolving: by denying Christ, he denies himself.', NULL),
  (59, 'And about the space of one hour after another confidently affirmed, saying, Of a truth this fellow also was with him: for he is a Galilaean.', 'καὶ διαστάσης ὡσεὶ ὥρας μιᾶς ἄλλος τις διϊσχυρίζετο λέγων, Ἐπ'' ἀληθείας καὶ οὗτος μετ'' αὐτοῦ ἦν· καὶ γὰρ Γαλιλαῖός ἐστιν.', 'kai diastasēs hōsei hōras mias allos tis diischurizeto legōn, Ep'' alētheias kai houtos met'' autou ēn; kai gar Galilaios estin.', '"About the space of one hour after" (diastasēs hōsei hōras mias — about one hour having intervened) — the interval between the second and third denials is the longest, as if Peter has relaxed. "Another confidently affirmed" (allos tis diischurizeto — another person was insisting strongly; diischurizomai = to maintain firmly, to assert emphatically; a strong verb indicating the accuser''s certainty). "Of a truth this fellow also was with him" (Ep'' alētheias — upon truth, certainly, truly) — the accusation claims certainty. "For he is a Galilaean" (Galilaios estin — he is a Galilean) — the evidence is Peter''s accent (cf. Matt 26:73), which distinguished Galilean dialect from Judean speech. Peter''s very speech betrays his identity.', NULL),
  (60, 'And Peter said, Man, I know not what thou sayest. And immediately, while he yet spake, the cock crew.', 'εἶπεν δὲ ὁ Πέτρος, Ἄνθρωπε, οὐκ οἶδα ὃ λέγεις. καὶ παραχρῆμα ἔτι λαλοῦντος αὐτοῦ ἐφώνησεν ἀλέκτωρ.', 'eipen de ho Petros, Anthrōpe, ouk oida ho legeis. kai parachrēma eti lalountos autou ephōnēsen alektōr.', '"Man, I know not what thou sayest" (Anthrōpe, ouk oida ho legeis — Man, I do not know what you are saying) — the third denial is the most comprehensive: Peter denies not just knowing Jesus but even understanding what the accuser is talking about. "Immediately" (parachrēma — on the spot, instantly; a Lucan favorite for divine timing). "While he yet spake, the cock crew" (eti lalountos autou ephōnēsen alektōr — while he was still speaking, a rooster crowed) — the prophecy of v.34 is fulfilled with devastating precision. The denial and the cockcrow overlap: Peter is literally mid-sentence when the rooster sounds. The timing is not coincidental but providentially orchestrated to fulfill Jesus'' word.', NULL),
  (61, 'And the Lord turned, and looked upon Peter. And Peter remembered the word of the Lord, how he had said unto him, Before the cock crow, thou shalt deny me thrice.', 'καὶ στραφεὶς ὁ Κύριος ἐνέβλεψεν τῷ Πέτρῳ, καὶ ὑπεμνήσθη ὁ Πέτρος τοῦ ῥήματος τοῦ Κυρίου ὡς εἶπεν αὐτῷ ὅτι Πρὶν ἀλέκτορα φωνῆσαι σήμερον ἀπαρνήσῃ με τρίς.', 'kai strapheis ho Kurios eneblepsen tō Petrō, kai hupemnēsthē ho Petros tou rhēmatos tou Kuriou hōs eipen autō hoti Prin alektora phōnēsai sēmeron aparnēsē me tris.', '"The Lord turned, and looked upon Peter" (strapheis ho Kurios eneblepsen tō Petrō — having turned, the Lord looked at Peter; emblepō = to look into, to gaze upon with penetrating intent) — this detail is unique to Luke and is one of the most emotionally powerful moments in the Passion Narrative. Jesus is being led through the courtyard (presumably between interrogation sessions) and catches Peter''s eye at the moment of the cockcrow. The look is not described as angry or condemning but simply as a direct gaze. The title "the Lord" (ho Kurios) at this moment of maximum humiliation maintains Jesus'' sovereign identity. "Peter remembered" (hupemnēsthē — was reminded, recalled; the look triggers the memory of Jesus'' prophecy). The look says what words cannot: I told you; I know; and yet I prayed for you (v.32).', NULL),
  (62, 'And Peter went out, and wept bitterly.', 'καὶ ἐξελθὼν ἔξω ἔκλαυσεν πικρῶς.', 'kai exelthōn exō eklausen pikrōs.', '"Went out" (exelthōn exō — having gone out, outside; the doubled expression emphasizes the departure from the courtyard into the darkness) — Peter leaves the fire, the crowd, and the scene of his failure. "Wept bitterly" (eklausen pikrōs — he wept bitterly; klaiō = to weep, to wail loudly, not silent tears but audible, broken weeping; pikrōs = bitterly, with sharp pain, with stinging grief) — the tears are not merely emotional but the convulsions of a soul recognizing the full extent of its betrayal. Peter''s bitter weeping is the counterpart to the tax collector''s breast-beating in 18:13: it is the response of genuine repentance. His failure is not the end of his story; Jesus has already prayed that his faith will not fail utterly (v.32), and the restoration will come (24:34; John 21:15-17).', NULL),
  (63, 'And the men that held Jesus mocked him, and smote him.', 'Καὶ οἱ ἄνδρες οἱ συνέχοντες αὐτὸν ἐνέπαιζον αὐτῷ δέροντες,', 'Kai hoi andres hoi sunechontes auton enepaizon autō derontes,', '"The men that held Jesus" (hoi andres hoi sunechontes auton — the men who were holding him, guarding him; sunechō = to hold together, to restrain, to guard). "Mocked him" (enepaizon autō — were mocking him, ridiculing him; empaizō = to play with, to mock, to make sport of; the imperfect tense: kept mocking). "Smote him" (derontes — beating, striking, flaying; derō literally = to skin, to flay, hence to beat severely) — the physical abuse begins before any formal trial. Luke places the mockery before the Sanhedrin trial (vv.66-71), whereas Mark places it after (Mark 14:65). The guards'' treatment of Jesus fulfills the third passion prediction: "he shall be mocked, and spitefully entreated" (18:32).', NULL),
  (64, 'And when they had blindfolded him, they struck him on the face, and asked him, saying, Prophesy, who is it that smote thee?', 'καὶ περικαλύψαντες αὐτὸν ἔτυπτον αὐτοῦ τὸ πρόσωπον καὶ ἐπηρώτων αὐτὸν λέγοντες, Προφήτευσον, τίς ἐστιν ὁ παίσας σε;', 'kai perikalupsantes auton etupton autou to prosōpon kai epērōtōn auton legontes, Prophēteuson, tis estin ho paisas se?', '"Blindfolded him" (perikalupsantes auton — having covered him around; perikaluptō = to cover completely, to veil) — blindfolding was part of the "game": Jesus is struck and then challenged to identify his assailant. "Struck him on the face" (etupton autou to prosōpon — were striking his face; tuptō = to strike, to hit) — the face, the seat of dignity and identity, is the target. "Prophesy, who is it that smote thee?" (Prophēteuson, tis estin ho paisas se — Prophesy! Who is the one who struck you?) — the demand is a cruel parody of prophetic power. The irony is devastating: while they mock his supposed inability to identify who struck him, he has already accurately prophesied Peter''s denial (fulfilled that very hour), the destruction of Jerusalem, and his own death and resurrection. They mock a prophet whose prophecies are being fulfilled around them.', NULL),
  (65, 'And many other things blasphemously spake they against him.', 'καὶ ἕτερα πολλὰ βλασφημοῦντες ἔλεγον εἰς αὐτόν.', 'kai hetera polla blasphēmountes elegon eis auton.', '"Many other things blasphemously spake they against him" (hetera polla blasphēmountes elegon eis auton — many other things blaspheming they were saying against him; blasphēmeō = to speak injuriously, to revile, to defame) — Luke summarizes rather than cataloguing the full extent of the verbal abuse. The word "blasphemously" (blasphēmountes) is deeply ironic: they will charge Jesus with blasphemy (v.71), yet it is they who commit the true blasphemy by reviling the Son of God. The verse functions as a transition from the mockery scene to the formal trial, indicating that the abuse continued throughout the night. The one against whom they blaspheme is the very one who will judge them.', NULL),
  (66, 'And as soon as it was day, the elders of the people and the chief priests and the scribes came together, and led him into their council, saying,', 'Καὶ ὡς ἐγένετο ἡμέρα, συνήχθη τὸ πρεσβυτέριον τοῦ λαοῦ, ἀρχιερεῖς τε καὶ γραμματεῖς, καὶ ἀπήγαγον αὐτὸν εἰς τὸ συνέδριον αὐτῶν λέγοντες,', 'Kai hōs egeneto hēmera, sunēchthē to presbuterion tou laou, archiereis te kai grammateis, kai apēgagon auton eis to sunedrion autōn legontes,', '"As soon as it was day" (hōs egeneto hēmera — when it became day; daylight is significant because Jewish legal procedure prohibited capital trials at night) — Luke places the Sanhedrin trial in the morning, not at night as in Mark 14:53-65, possibly reflecting a more legally regular procedure or a distinct tradition. "The elders of the people and the chief priests and the scribes" (to presbuterion tou laou, archiereis te kai grammateis — the council of elders of the people, both chief priests and scribes) — the three constituent groups of the Sanhedrin, Israel''s supreme judicial body. "Their council" (to sunedrion autōn — their Sanhedrin/council; sunedrion from sun/together + hedra/seat = a sitting together, a judicial assembly).', NULL),
  (67, 'Art thou the Christ? tell us. And he said unto them, If I tell you, ye will not believe:', 'Εἰ σὺ εἶ ὁ Χριστός, εἰπὲ ἡμῖν. εἶπεν δὲ αὐτοῖς, Ἐὰν ὑμῖν εἴπω, οὐ μὴ πιστεύσητε·', 'Ei su ei ho Christos, eipe hēmin. eipen de autois, Ean humin eipō, ou mē pisteusēte;', '"Art thou the Christ?" (Ei su ei ho Christos — If you are the Christ/Messiah; the question is the central issue: is Jesus the anointed one, the Messiah of Israel?) — the Sanhedrin seeks a direct claim that can be used as a basis for charges before Pilate. "If I tell you, ye will not believe" (Ean humin eipō, ou mē pisteusēte — if I tell you, you will certainly not believe) — Jesus''s response exposes the bad faith of the question: they are not seeking truth but evidence for condemnation. The double negative ou mē (certainly not) indicates Jesus''s certainty about their unbelief. The response echoes John 10:25-26: "I told you, and ye believed not." Jesus refuses to provide a simple answer to a question asked in bad faith, while simultaneously giving an answer that reveals both his identity and their culpability.', NULL),
  (68, 'And if I also ask you, ye will not answer me, nor let me go.', 'ἐὰν δὲ ἐρωτήσω, οὐ μὴ ἀποκριθῆτε.', 'ean de erōtēsō, ou mē apokrithēte.', '"If I also ask you, ye will not answer me" (ean de erōtēsō, ou mē apokrithēte — and if I ask, you will certainly not answer) — Jesus exposes the procedural injustice: a genuine trial would involve dialogue and examination, but this is a predetermined verdict in search of evidence. The double negative again (ou mē) indicates certainty. "Nor let me go" — some manuscripts include this clause (ou mē apolusēte), others omit it. If original, it makes explicit that acquittal is not possible regardless of Jesus'' response. The verse unmasks the trial as theater: the conclusion was decided before the questioning began. Jesus participates in the trial not as a defendant seeking acquittal but as a prophet announcing judgment.', NULL),
  (69, 'Hereafter shall the Son of man sit on the right hand of the power of God.', 'ἀπὸ τοῦ νῦν δὲ ἔσται ὁ Υἱὸς τοῦ ἀνθρώπου καθήμενος ἐκ δεξιῶν τῆς δυνάμεως τοῦ Θεοῦ.', 'apo tou nun de estai ho Huios tou anthrōpou kathēmenos ek dexiōn tēs dunameōs tou Theou.', '"Hereafter" (apo tou nun — from now on, from this moment forward) — Luke''s "from now on" replaces Mark''s "ye shall see" (Mark 14:62), emphasizing that Jesus'' exaltation begins immediately, not at some distant future point. The Passion itself is the beginning of his enthronement. "The Son of man sit on the right hand of the power of God" (ho Huios tou anthrōpou kathēmenos ek dexiōn tēs dunameōs tou Theou — the Son of Man seated at the right hand of the power of God) — a composite allusion to Psalm 110:1 ("Sit thou at my right hand") and Daniel 7:13-14 (the Son of Man receiving dominion). "The power of God" (tēs dunameōs tou Theou) is a reverent circumlocution for God himself. The claim is extraordinary: the prisoner before the Sanhedrin declares that he will occupy the position of supreme cosmic authority alongside God.', NULL),
  (70, 'Then said they all, Art thou then the Son of God? And he said unto them, Ye say that I am.', 'εἶπαν δὲ πάντες, Σὺ οὖν εἶ ὁ Υἱὸς τοῦ Θεοῦ; ὁ δὲ πρὸς αὐτοὺς ἔφη, Ὑμεῖς λέγετε ὅτι ἐγώ εἰμι.', 'eipan de pantes, Su oun ei ho Huios tou Theou? ho de pros autous ephē, Humeis legete hoti egō eimi.', '"Art thou then the Son of God?" (Su oun ei ho Huios tou Theou — You then are the Son of God?) — the Sanhedrin draws the inference from v.69: if Jesus claims to sit at God''s right hand, he claims divine sonship. The question moves from "Christ" (v.67) to "Son of God" — a higher category. "Ye say that I am" (Humeis legete hoti egō eimi — You say that I am; or: You are saying that I am) — the response is affirmative but expressed with judicial reserve: Jesus does not deny the title but places the confession in their mouths. The phrase egō eimi (I am) carries resonance with the divine name (Exod 3:14). Jesus neither evades nor elaborates; he affirms by placing responsibility on the questioners to recognize what they themselves are saying.', NULL),
  (71, 'And they said, What need we any further witness? for we ourselves have heard of his own mouth.', 'οἱ δὲ εἶπαν, Τί ἔτι ἔχομεν μαρτυρίας χρείαν; αὐτοὶ γὰρ ἠκούσαμεν ἀπὸ τοῦ στόματος αὐτοῦ.', 'hoi de eipan, Ti eti echomen marturias chreian? autoi gar ēkousamen apo tou stomatos autou.', '"What need we any further witness?" (Ti eti echomen marturias chreian — What further need of testimony do we have?) — the Sanhedrin considers Jesus''s own words sufficient evidence; no additional witnesses are required. "We ourselves have heard of his own mouth" (autoi gar ēkousamen apo tou stomatos autou — for we ourselves heard from his mouth) — his self-testimony condemns him in their judgment. The irony is multi-layered: they convict him for claiming to be what he actually is. The "blasphemy" they perceive is in fact the truth they cannot recognize. Their verdict is legally based on his own words, making Jesus simultaneously the accused, the key witness, and — from the reader''s perspective — the judge of his own judges. The trial ends without a formal verdict in Luke; the action moves immediately to Pilate (23:1).', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 22;

-- LUKE CHAPTER 22 — BACKFILL (word_studies + cross_references)

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'ἀζύμων', 'azumōn', 'G106', 'Unleavened (bread) — the feast of unleavened bread (ta Azuma), beginning the day after Passover (14 Nisan) and running seven days. Luke conflates it with Passover, as was common usage. Leaven symbolized corruption, so its removal embodied purification in preparation for the redemptive meal.', 1),
  (1, 'πάσχα', 'pascha', 'G3957', 'Passover — from Hebrew pesach (to pass over); the annual commemoration of God''s deliverance from Egypt (Exod 12). The feast frames the entire Passion: Jesus is the true Passover Lamb whose blood averts judgment (1 Cor 5:7).', 2),
  (3, 'Σατανᾶς', 'Satanas', 'G4567', 'Satan — the Adversary; Hebrew ha-satan, the accuser. Luke uniquely marks Judas''s betrayal as Satan''s entry into him (also John 13:27), framing the Passion as spiritual warfare culminating the wilderness conflict (4:13 — Satan departed "until an opportune time").', 1),
  (3, 'Ἰσκαριώτην', 'Iskariōtēn', 'G2469', 'Iscariot — likely from Hebrew ish Qeriyot (man of Kerioth, a town in Judah), distinguishing Judas from others of the same name. Some propose derivation from Latin sicarius (dagger-man/assassin), but the geographic reading is favored.', 2),
  (4, 'στρατηγοῖς', 'stratēgois', 'G4755', 'Captains (of the temple) — the temple police officers under the sagan (captain of the temple), responsible for order on the temple mount. Their involvement shows the arrest was a religio-political operation with temple authority behind it.', 1),
  (6, 'ἐξωμολόγησεν', 'exōmologēsen', 'G1843', 'Agreed/consented (fully) — literally "confessed out," publicly gave his word/undertaking. Judas enters into a formal contract with the authorities, sealing his betrayal with a binding commitment before opportunity arose.', 1),
  (6, 'ἄτερ ὄχλου', 'ater ochlou', 'G817', 'Away from/apart from the crowd — Judas'' contribution was intelligence on Jesus'' private location (Gethsemane), enabling an arrest that bypassed popular opposition. The crowd''s favor (19:48) is the obstacle the plot must circumvent.', 2),
  (15, 'ἐπιθυμίᾳ ἐπεθύμησα', 'epithumia epethumēsa', 'G1939', 'With desire I have desired — Hebraic cognate accusative intensifying the verb: "I have earnestly longed." Jesus''s yearning to share this meal before his suffering reveals the Passover''s climactic significance for him; he has approached it as the goal of his ministry.', 1),
  (19, 'ἀνάμνησιν', 'anamnēsin', 'G364', 'Remembrance/memorial — a calling-back-to-mind that makes past redemption present. The Passover was likewise a zikkaron (Exod 12:14); Jesus institutes a new memorial that reenacts his body-given sacrifice for his people.', 1),
  (20, 'διαθήκη', 'diathēkē', 'G1242', 'Covenant/testament — a legally binding disposition (not a mutual "contract" but a sovereignly enacted arrangement). Jesus fulfills the "new covenant" promised in Jer 31:31-34, ratified in his blood as Sinai''s covenant was in sacrificial blood (Exod 24:8).', 1),
  (20, 'ἐκχυννόμενον', 'ekchunnomenon', 'G1632', 'Poured out/shed — the present passive participle echoes the servant of Isa 53:12 who "poured out his soul unto death." The cup-blood idiom evokes sacrificial altar pouring (Lev 4:7) fused with the Servant''s substitutionary self-offering.', 2),
  (22, 'ὡρισμένον', 'hōrismenon', 'G3724', 'Determined/appointed — from horizō (to mark out a horizon, to ordain). The Son of Man goes "according to what has been determined," affirming divine predestination; yet human responsibility is not cancelled ("woe unto that man"). Both realities stand unresolved.', 1),
  (25, 'εὐεργέται', 'euergetai', 'G2110', 'Benefactors — an honorific title assumed by Hellenistic rulers (e.g., Ptolemy III Euergetes, Antiochus VII Euergetes) claiming to be patrons of their subjects. Jesus exposes the self-congratulatory rhetoric: they lord it over, yet style themselves as benefactors.', 1),
  (27, 'διακονῶν', 'diakonōn', 'G1247', 'The one serving — Jesus defines his own identity through table-service, the posture of a slave in a Greco-Roman banquet. The Lord at table as servant overturns the entire hierarchy of the reclining dinner and prefigures the foot-washing (John 13).', 1),
  (31, 'σινιάσαι', 'siniasai', 'G4617', 'To sift — the violent agitation of wheat in a sieve to separate chaff from grain. Satan''s request (echoing Job 1:6-12) is for permission to test/shatter the disciples. Sifting separates but can also destroy when done brutally.', 1),
  (31, 'ἐξῃτήσατο', 'exētēsato', 'G1809', 'Demanded/requested out — the aorist middle indicates formal, urgent petition. Satan has obtained clearance to attack — the Job-pattern: the Adversary must seek God''s warrant before afflicting the saints.', 2),
  (32, 'ἐκλίπῃ', 'eklipē', 'G1587', 'Fail/give out — lit. "be eclipsed," to fade away to nothing. Jesus prays not that Peter be spared sifting but that his faith not utterly collapse under it. Denial ≠ apostasy; the intercession preserves him.', 1),
  (32, 'ἐπιστρέψας', 'epistrepsas', 'G1994', 'Having turned back/returned — the technical word for conversion/return to God. Jesus anticipates Peter''s fall AND his restoration, already commissioning his post-restoration ministry to his brethren.', 2),
  (32, 'στήρισον', 'stērison', 'G4741', 'Strengthen/establish — to make firm, buttress, set fast. Peter''s own experience of failure-and-restoration becomes the very credential for strengthening the brethren — the shepherd who was himself brought back (John 21:15-17).', 3),
  (37, 'τελεσθῆναι', 'telesthēnai', 'G5055', 'To be fulfilled/completed — Jesus explicitly cites Isa 53:12 ("reckoned with transgressors") as about to reach its telos in him. This is Luke''s clearest servant-song Passion quotation: the Passion is not catastrophe but the scheduled completion of Isaiah 53.', 1),
  (37, 'ἀνόμων', 'anomōn', 'G459', 'Lawless/transgressors — from anomos (without law). Jesus will be "numbered with" criminals (fulfilled 23:33 — crucified between two malefactors), satisfying Isa 53:12 LXX exactly (kai en tois anomois elogisthē).', 2),
  (42, 'παρενέγκαι', 'parenenkai', 'G3911', 'Take away/remove (aside) — from parapherō (carry past/alongside). Jesus''s request is real (not performative): he truly recoils from the cup. Yet the request is framed within "if thou be willing," subordinating even his deepest desire to the Father.', 1),
  (42, 'ποτήριον', 'potērion', 'G4221', 'Cup — in OT imagery, the "cup" of God''s wrath (Ps 75:8; Isa 51:17; Jer 25:15-28) is drunk by the objects of judgment. Jesus drinks this cup in the place of sinners; the horror of Gethsemane is the horror of absorbing divine wrath.', 2),
  (43, 'ἐνισχύων', 'enischuōn', 'G1765', 'Strengthening — an angel intensifies Jesus''s capacity to endure the agony. The scene (textually disputed — omitted by some early mss) parallels the angelic ministry after the wilderness temptation (Mark 1:13), framing Gethsemane as the final climactic peirasmos.', 1),
  (44, 'ἀγωνίᾳ', 'agōnia', 'G74', 'Agony — the struggle/conflict of an athlete at the decisive moment of the contest; the extreme tension before an all-out exertion. Not "anxiety" in the weak modern sense but the convulsive effort of a combatant at the breaking point.', 1),
  (44, 'θρόμβοι αἵματος', 'thromboi haimatos', 'G2361', 'Drops/clots of blood — thromboi = thick drops, coagulated masses. The expression "like drops of blood" likely refers to hematidrosis (sweating blood under extreme duress, medically attested). The medical language coheres with Luke''s physician''s eye.', 2),
  (46, 'πειρασμόν', 'peirasmon', 'G3986', 'Temptation/trial — the decisive test. Jesus''s double command to pray "lest ye enter into peirasmos" (vv.40, 46) frames Gethsemane as the eschatological trial. The disciples sleep through their summons to vigilance and soon fail (flee, deny).', 1),
  (48, 'φιλήματι', 'philēmati', 'G5370', 'With a kiss — the customary disciple-to-teacher greeting, now perverted into a betrayer''s identifying sign. The horror: the sign of affection becomes the weapon of treachery. Jesus''s question ("betrayest thou the Son of man with a kiss?") exposes the sacrilege.', 1),
  (51, 'Ἐᾶτε ἕως τούτου', 'Eate heōs toutou', 'G1439', 'Suffer/permit ye thus far — an enigmatic rebuke: "let them go even to this point" (i.e., the disciples'' resistance has gone far enough) or "permit me this one final act" (the healing of the ear). Luke alone records the healing — the last miracle of Jesus''s ministry is a healing of an enemy.', 1),
  (53, 'ἐξουσία τοῦ σκότους', 'exousia tou skotous', 'G4655', 'Power/authority of darkness — not mere nightfall but the authorized reign of evil over this hour. Jesus identifies his arrest as the interval when darkness has been granted jurisdiction (cf. John 14:30 "the prince of this world cometh"). The hour is real but bounded.', 1),
  (61, 'στραφεὶς', 'strapheis', 'G4762', 'Having turned — the Lord physically turns and locks eyes with Peter from across the courtyard. Unique to Luke, this silent look completes the prophecy of v.34 and becomes the trigger of Peter''s repentance. The look says everything without a word.', 1),
  (61, 'ἐνέβλεψεν', 'eneblepsen', 'G1689', 'Looked upon/gazed at — from emblepō (to look into with fixed intent). Not a casual glance; a penetrating, meaning-laden look. This gaze pierces Peter more than any rebuke; the reality of the denial crystallizes in Jesus''s eyes.', 2),
  (62, 'πικρῶς', 'pikrōs', 'G4090', 'Bitterly — adverb from pikros (bitter, sharp, piercing). Peter''s tears are not quiet but sharply piercing — the grief of a soul that sees itself truly for the first time. The bitterness is the taste of godly repentance (2 Cor 7:10) that leads back, not of despair.', 1),
  (64, 'Προφήτευσον', 'Prophēteuson', 'G4395', 'Prophesy! — the mockery demands he identify blindfolded who struck him, a cruel parody of his prophetic claims. The devastating irony: his prophecies of Peter''s denial (just fulfilled), the Temple''s fall, and his own resurrection are being vindicated as they mock.', 1),
  (66, 'συνέδριον', 'sunedrion', 'G4892', 'Sanhedrin/council — the supreme Jewish judicial council of 71 members (Num 11:16-17 is its traditional basis). Luke alone notes the trial occurred at daybreak, possibly distinguishing a formal morning session from a preliminary night interrogation.', 1),
  (69, 'ἐκ δεξιῶν', 'ek dexiōn', 'G1188', 'At/on the right hand — the position of supreme honor and executive authority. The allusion fuses Ps 110:1 (sit thou at my right hand) with Dan 7:13-14 (the Son of Man receiving dominion). The prisoner in the dock announces that he will rule from God''s throne.', 1),
  (69, 'δυνάμεως', 'dunameōs', 'G1411', 'Power — here as reverent circumlocution for God himself (a rabbinic idiom, cf. Matt 26:64 "the Power"). Avoiding the divine name while claiming the divine throne, Jesus makes an unmistakable claim without directly pronouncing it.', 2),
  (70, 'Ὑμεῖς λέγετε', 'Humeis legete', 'G3004', 'Ye say — an affirmative answer in a juridical register: "it is you who are saying it" = yes, with the responsibility for the utterance placed on the questioner. The emphatic humeis acknowledges the claim while refusing to make it a flat denial target.', 1),
  (70, 'ἐγώ εἰμι', 'egō eimi', 'G1510', 'I am — pregnant with the divine self-identification of Exod 3:14 LXX (egō eimi ho ōn) and the Johannine I-am sayings. Even in Luke''s comparatively restrained formulation, the confession resonates with the divine name.', 2)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Luke' AND c.chapter_number = 22 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

